// BaaS config for the Canagrou SPA. Injected at runtime by public/baas-config.js
// (window.__BAAS__), generated by scripts/seed/canagrou-tenant.sh — no bundler
// step, so there is no import.meta.env dependency.

const cfg = (typeof window !== 'undefined' && window.__BAAS__) || {};

export const config = cfg;

const REQUIRED = ['url', 'anonKey', 'apiKey', 'dbId', 'storageBucket', 'storageToken', 'realtimeToken'];

/**
 * assertConfigured throws a clear error when the generated BaaS config is
 * missing a field, pointing the developer at the provisioning script.
 */
export function assertConfigured() {
  const missing = REQUIRED.filter((k) => !cfg[k]);
  if (missing.length) {
    throw new Error(
      `Canagrou: BaaS config missing [${missing.join(', ')}] — run ` +
        '`bash scripts/seed/canagrou-tenant.sh` to (re)generate web/public/baas-config.js',
    );
  }
}
